insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m1$L4W$, $L4W$delegation$L4W$, $L4W$Foundations$L4W$, $L4W$From individual contributor to people manager$L4W$, $L4W$What changes when you stop doing and start enabling.$L4W$, 4, 1, $L4W$[{"kind":"hook","title":"From individual contributor to people manager","body":["You used to be rewarded for getting your own work done. Now your success depends on how well your team performs.","If you keep working the way you did as an IC, you'll feel overloaded — and your team won't grow."]},{"kind":"compare","title":"Your job has changed (even if nobody said it clearly)","leftLabel":"Individual contributor","rightLabel":"People manager","left":["I finish my tasks.","I'm the expert with the answers.","My success = my personal output."],"right":["My team hits our goals.","I create clarity and remove blockers.","My success = our collective output."],"highlight":"You're moving from 'How can I do more?' to 'How can we do better?'"},{"kind":"dragdrop","title":"Are these IC or manager behaviours?","prompt":"Drag each statement into the bucket where it mostly belongs today. Go with your first instinct.","leftLabel":"Individual contributor","rightLabel":"People manager","items":[{"text":"I fix problems myself so it's faster.","side":"left"},{"text":"I ask what they think before I share my view.","side":"right"},{"text":"I stay late to finish other people's tasks.","side":"left"},{"text":"I define what success looks like, then let the team find the 'how'.","side":"right"},{"text":"I redo work if it's not exactly my style.","side":"left"},{"text":"I plan 1:1s and feedback conversations each week.","side":"right"}]},{"kind":"selfcheck","title":"Which trap sounds most like you right now?","prompt":"Most new managers get stuck in at least one. Pick the closest.","options":[{"text":"I keep jumping in to fix everything (still the hero).","response":"Great self-awareness. We'll help you move from hero to coach."},{"text":"I'm juggling a full IC workload plus managing on the side.","response":"You're not alone. Time and focus are big challenges in year one."},{"text":"I avoid tough conversations and hope things improve.","response":"Very common. We'll practise small, safe steps into tough talks."},{"text":"I don't want to upset my old peers, so I hold back.","response":"Leading former peers is tricky. We'll work on boundaries and clarity."}]},{"kind":"lesson","title":"The manager mindset: 3 shifts","points":[{"h":"From doing to enabling","p":"From 'How can I fix this?' to 'How do I set things up so my team can handle it well?'"},{"h":"From answers to questions","p":"Instead of giving the solution, start with 'What do you think we should do?'"},{"h":"From short-term fixes to long-term growth","p":"Still hit today's deadlines, but invest in coaching, feedback, and better processes."}],"note":"These aren't personality traits. They're learnable skills — we'll practise them in tiny steps."},{"kind":"scenario","title":"Scenario: what do you do?","setup":"A team member pings you: 'This client email is tricky — can you tell me exactly what to reply?' You're busy and want it done quickly.","question":"What do you do most often today (be honest)?","choices":[{"text":"Quickly write the reply for them so it's correct.","feedback":"Still hero mode. Fast short-term, but they stay dependent on you."},{"text":"Ignore it until later, then rush it yourself.","feedback":"Understandable when overloaded, but it grows your stress and not your team."},{"text":"Ask them to draft a reply, then review it together.","feedback":"A classic manager move: you enable, coach, and still protect quality.","best":true}],"followUp":"Over this journey we'll help you reach the third option more often — without slowing everything down."},{"kind":"action","title":"Today's action: one small shift","intro":"In the next 24 hours, when a team member asks for help, try this:","steps":["Instead of answering, ask: 'Before I share my view, what do you think we should do?'","Listen fully. Ask one follow-up question.","Decide together on the final approach."],"note":"You're practising two shifts at once: doing → enabling, and answers → questions."},{"kind":"reflect","title":"How did your first shift feel?","scaleQuestion":"How hard was it not to jump in with the answer?","scaleOptions":["Very hard","Hard","Okay","Easy","Very easy"],"textPrompt":"What surprised you about your team member's idea?","placeholder":"They suggested…","closing":"Every time you do this, you build your manager muscle. Small reps, big change."}]$L4W$::jsonb);
insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m2$L4W$, $L4W$listening$L4W$, $L4W$Foundations$L4W$, $L4W$Manager mindset & emotional intelligence$L4W$, $L4W$Manage your own reactions before you manage others.$L4W$, 4, 2, $L4W$[{"kind":"hook","title":"Your first tool as a manager: your emotions","body":["As an IC you were judged on your skills and output.","As a manager, your emotional reactions — your tone, your calm, your empathy — can build or break trust in seconds.","Emotional intelligence is the quiet superpower of great managers."]},{"kind":"lesson","title":"Emotional intelligence in your day-to-day","points":[{"h":"Self-awareness","p":"Noticing what you feel and how you come across — especially when stressed."},{"h":"Self-regulation","p":"Choosing your response instead of reacting on autopilot."},{"h":"Empathy","p":"Understanding what your team might be feeling, even when unspoken."}],"note":"You can't control everything that happens, but you can control how you show up."},{"kind":"dragdrop","title":"Reacting or responding?","prompt":"React = fast and emotional. Respond = calm and intentional. Sort each one.","leftLabel":"Reacting","rightLabel":"Responding","items":[{"text":"Firing off a sharp message in chat the moment you see a mistake.","side":"left"},{"text":"Taking a breath and asking 'What happened here?' before commenting.","side":"right"},{"text":"'We've talked about this — why are you still getting it wrong?'","side":"left"},{"text":"'Let's walk through what made this hard and what support you need.'","side":"right"},{"text":"Going silent and avoiding the person for days.","side":"left"},{"text":"Booking a short 1:1 to share impact, listen, and agree next steps.","side":"right"}]},{"kind":"selfcheck","title":"When you're under pressure, you tend to…","options":[{"text":"Get sharp or impatient — people feel my frustration.","response":"You care a lot. We'll protect people from the rough edges of that."},{"text":"Shut down or go quiet — I avoid conversations.","response":"Silence can feel scary to others too. We'll practise safe ways to speak up."},{"text":"Over-control — micromanage, double-check, take work back.","response":"You want things to go well. We'll help you trust and coach more."},{"text":"Stay mostly calm — but it takes effort.","response":"Great. We'll still sharpen your awareness and empathy."}]},{"kind":"scenario","title":"Scenario: the missed deadline","setup":"A key report your team promised another department is late. They're upset and copying your boss. You feel a rush of stress.","question":"What do you do in the first 2 minutes?","choices":[{"text":"Send a tough message: 'This is unacceptable. We're making the whole group look bad.'","feedback":"A reaction. It releases your stress but creates fear — and less honesty next time."},{"text":"Say nothing, take the report on yourself, stay late, and resent the team.","feedback":"Another reaction — shut down and rescue. Work gets done, nobody learns, your stress grows."},{"text":"Pause, notice what you feel, then: 'Let's jump on a quick call to understand what happened.'","feedback":"A response — still addressing it, but with curiosity and respect.","best":true}],"followUp":"EI doesn't mean pretending you're not upset. It means not letting your first emotion choose your next move."},{"kind":"action","title":"Today's action: the 10-second pause","intro":"Today, when something triggers you — a mistake, a comment, an email — try this:","steps":["Pause for one deep breath.","Name your feeling silently: 'I'm frustrated / anxious.'","Choose one manager question: 'Can you walk me through what happened?'"],"note":"You're training your brain to respond like a manager, not react like a stressed IC."},{"kind":"reflect","title":"How did your 10-second pause go?","scaleQuestion":"How often did you pause before reacting yesterday?","scaleOptions":["0 times","1 time","2–3 times","4+ times"],"textPrompt":"What changed in the conversation when you paused first?","placeholder":"When I paused…","closing":"Every pause builds your self-awareness and self-control. That's EI in action."}]$L4W$::jsonb);
insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m3$L4W$, $L4W$conflict$L4W$, $L4W$Foundations$L4W$, $L4W$Trust, psychological safety & inclusion$L4W$, $L4W$Make it safe to speak up, disagree, and admit mistakes.$L4W$, 4, 3, $L4W$[{"kind":"hook","title":"If they don't feel safe, they won't tell you the truth","body":["Your team can only fix problems they're willing to talk about.","If people fear being judged, blamed, or ignored, they hide issues, ideas, and mistakes.","Your daily behaviour decides: 'Is it safe to speak up here?'"]},{"kind":"lesson","title":"Psychological safety, in real language","points":[{"h":"Ask without fear","p":"People can ask questions without feeling stupid."},{"h":"Admit mistakes","p":"People can own mistakes without being shamed."},{"h":"Share concerns","p":"People can raise ideas or risks without fear of payback."}],"note":"It doesn't mean everyone is always comfortable. It means it's safe to be honest."},{"kind":"dragdrop","title":"Do these build or break safety?","prompt":"Sort each behaviour into the right bucket.","leftLabel":"Builds safety","rightLabel":"Breaks safety","items":[{"text":"Laughing when someone asks a basic question in a meeting.","side":"right"},{"text":"'Thank you for raising this' when someone shares a risk.","side":"left"},{"text":"In front of others: 'Why can't you get this right?'","side":"right"},{"text":"Sharing one of your own past mistakes and what you learned.","side":"left"},{"text":"Ignoring a concern because a quieter person raised it.","side":"right"},{"text":"Inviting quieter people by name: 'I'd love your view on this.'","side":"left"}]},{"kind":"selfcheck","title":"Right now, my team would say…","prompt":"How safe is it to speak honestly to me about problems?","options":[{"text":"Very safe — they tell me almost everything.","response":"Great. We'll keep reinforcing the behaviours that created this."},{"text":"Mostly safe — they tell me many things.","response":"Good base. Small changes can unlock even more honesty."},{"text":"Mixed — some things are left unsaid.","response":"Awareness is the first step. We'll start with one small change this week."},{"text":"Not very safe — they often hold back.","response":"Awareness is the first step. We'll start with one small change this week."}]},{"kind":"scenario","title":"Scenario: the public mistake","setup":"In a team meeting, someone shares a report with a clear mistake. Another department is on the call. You feel embarrassed and frustrated.","question":"What do you say or do?","choices":[{"text":"In front of everyone: 'This is wrong. We can't present work like this.'","feedback":"A common reaction — but it breaks safety. People learn to hide mistakes, not surface them."},{"text":"Say nothing in the meeting, then send a long angry message later.","feedback":"Kinder in public, but private anger still creates fear of bringing you unfinished work."},{"text":"'Thanks for putting this together. There's a mistake — let's fix it and talk after about what made it hard.'","feedback":"Addresses the issue and protects safety. You separate the person from the problem.","best":true}],"followUp":"Psychological safety isn't ignoring mistakes. It's how you respond when they happen."},{"kind":"action","title":"Today's action: reward the risk of speaking up","intro":"In your next meeting or 1:1, do one of these:","steps":["When someone shares a concern: 'Thank you for raising this. Let's look at it together.'","Ask a quieter person by name: 'I'd really like to hear your thoughts.'","Share one small mistake you've made and what you learned."],"note":"People repeat what gets rewarded, not punished."},{"kind":"reflect","title":"What changed when you rewarded honesty?","scaleQuestion":"How did your team react when you thanked them or invited their view?","scaleOptions":["Shut down","Neutral","A bit more open","Clearly more open"],"textPrompt":"What did you notice about the energy in the conversation?","placeholder":"I noticed…","closing":"Every time you reward speaking up, you invest in trust. Over time, that becomes your team's culture."}]$L4W$::jsonb);
insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m4$L4W$, $L4W$communication$L4W$, $L4W$Communication & listening$L4W$, $L4W$Communication foundations$L4W$, $L4W$Be clear: outcome, context, and a check-back.$L4W$, 4, 4, $L4W$[{"kind":"hook","title":"Saying it once ≠ clear communication","body":["Most new managers say: 'But I told them what to do.'","If your message isn't clear, specific, and checked for understanding, your team will guess — and you'll be disappointed.","Your job isn't just to talk. It's to make sure the message lands."]},{"kind":"lesson","title":"Clear communication = 3 ingredients","points":[{"h":"Outcome","p":"What does 'done' look like? 'A one-page summary with 3 options by Friday', not 'fix the deck'."},{"h":"Context","p":"Why does it matter? 'This is for a client decision; they care about cost and risk.'"},{"h":"Check-back","p":"'Can you tell me in your own words what you'll deliver and by when?'"}],"note":"If any of these are missing, your team is guessing."},{"kind":"dragdrop","title":"Clarity or confusion?","prompt":"Sort each statement into the right bucket.","leftLabel":"Builds clarity","rightLabel":"Creates confusion","items":[{"text":"'Just get this to me ASAP.'","side":"right"},{"text":"'Send a one-page summary of the top 3 risks by Thursday 3pm.'","side":"left"},{"text":"'You know what I mean, right?'","side":"right"},{"text":"'This is for leadership — keep it high-level, focused on impact.'","side":"left"},{"text":"'Sort it out with the others.'","side":"right"},{"text":"'You own the first draft; I'll review once before it goes out.'","side":"left"}]},{"kind":"selfcheck","title":"When I assign tasks, I usually…","options":[{"text":"Say what I need roughly and expect them to figure it out.","response":"Fast short-term, but it leads to rework. We'll start upgrading this."},{"text":"Give some detail but rarely check what they understood.","response":"On the right path — adding a check-back will level this up."},{"text":"Explain the outcome and context, and ask them to repeat the plan.","response":"Great foundation. We'll make this consistent and efficient."}]},{"kind":"scenario","title":"Scenario: handing off an important task","setup":"You need a team member to prepare a quick update for leadership on a customer issue. They're busy, you're busy, but it's important.","question":"What do you actually say most often?","choices":[{"text":"'Can you put something together for leadership about the issue?'","feedback":"Better than nothing, but still vague. 'Something' means different things to each of you."},{"text":"'Can you handle the leadership update?' (no details)","feedback":"Maximum confusion — they might not know format, level, or deadline."},{"text":"'Send a 3–4 slide update by 11am tomorrow: what happened, impact, recommended next step.'","feedback":"Clear outcome, structure, and deadline. Add a check-back and you're solid.","best":true}],"followUp":"Add one line to make it complete: 'Can you recap what you'll send and when?'"},{"kind":"action","title":"Today's action: define 'done' clearly once","intro":"Pick one task you'll assign today. Include these 3 pieces:","steps":["Outcome: 'This is what done looks like…'","Deadline: 'I need it by…'","Check-back: 'Can you tell me in your own words what you'll deliver and by when?'"],"note":"You don't need to talk more. You need to talk more clearly about what matters."},{"kind":"reflect","title":"Did your clear ask change anything?","scaleQuestion":"How clear did your task feel to them this time?","scaleOptions":["Still lots of questions","Somewhat clearer","Clear","Very clear, almost no follow-ups"],"textPrompt":"What did you notice about their questions or the quality of their work?","placeholder":"I noticed…","closing":"Every time you define 'done' clearly, you save time later and build trust that you're a clear, reliable leader."}]$L4W$::jsonb);
insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m5$L4W$, $L4W$listening$L4W$, $L4W$Communication & listening$L4W$, $L4W$Active listening & better questions$L4W$, $L4W$Listen to understand, and ask before you advise.$L4W$, 4, 5, $L4W$[{"kind":"hook","title":"Listening is your most underrated power","body":["Managers spend much of the day in conversations — but few are trained to listen well.","When you listen actively, people feel safe and honest. You spot problems earlier and build trust faster.","Listening well is often more powerful than the perfect advice."]},{"kind":"lesson","title":"Active listening = 3 moves","points":[{"h":"Presence","p":"Remove distractions, make eye contact, give full attention."},{"h":"Reflect & clarify","p":"Reflect key points: 'So you're saying…' and ask clarifying questions."},{"h":"Curious questions","p":"Ask 'What happened next?' or 'How did that feel?' instead of jumping to solutions."}],"note":"Your goal isn't to talk less. It's to understand more before you speak."},{"kind":"dragdrop","title":"Listening or pretending?","prompt":"Sort each behaviour into the right bucket.","leftLabel":"Active listening","rightLabel":"Pretending to listen","items":[{"text":"Checking your phone while someone is talking.","side":"right"},{"text":"'Tell me more about that' — then staying quiet.","side":"left"},{"text":"Formulating your reply while they're still speaking.","side":"right"},{"text":"'If I heard you right, the main issue is…'","side":"left"},{"text":"Cutting in with 'Yeah, yeah, I get it, here's what to do…'","side":"right"},{"text":"'What was the hardest part of that for you?'","side":"left"}]},{"kind":"selfcheck","title":"In most 1:1s, I tend to…","options":[{"text":"Talk more than I listen — explaining, advising, updating.","response":"Very common for new managers. We'll help you flip this gradually."},{"text":"Listen at first, then jump in quickly with my opinions.","response":"Partway there — adding 1–2 good questions will unlock a lot."},{"text":"Let them talk, reflect back, and ask follow-up questions.","response":"Great habit. We'll sharpen your questions even more."}]},{"kind":"scenario","title":"Scenario: your team member shares a concern","setup":"In a 1:1, your team member says: 'Honestly, I've been feeling overwhelmed and I'm not sure I'm doing a good job.'","question":"What do you say first?","choices":[{"text":"'Don't worry, you're doing fine. Anyway, here are our priorities…'","feedback":"Comes from a good place, but shuts the door. They learn not to bring early signals to you."},{"text":"'Why are you overwhelmed? We all have a lot on our plates.'","feedback":"'Why' can feel like judgement. They may get defensive instead of opening up."},{"text":"'Thanks for telling me. Can you tell me more about what's felt overwhelming lately?'","feedback":"An active-listening response. You acknowledge their courage and invite more without judging.","best":true}],"followUp":"Good follow-ups start with 'what' or 'how', not 'why': 'What's been the toughest part?'"},{"kind":"action","title":"Today's action: the 70/30 rule","intro":"In your next 1:1 or meaningful conversation, try this:","steps":["Remove distractions for 10–15 minutes (no phone).","Aim for them to talk ~70% of the time, you 30%.","Ask one open question: 'What's been most challenging this week?'"],"note":"You're practising two skills at once: full attention, and better questions."},{"kind":"reflect","title":"Did your listening change the conversation?","scaleQuestion":"In that 1:1, who talked more?","scaleOptions":["I talked most","About 50/50","They talked more"],"textPrompt":"What did you hear this time that you might have missed before?","placeholder":"I heard…","closing":"When people feel truly heard, they're more honest and more committed. That's the real power of listening."}]$L4W$::jsonb);
insert into public.modules (id, skill, cluster, title, summary, minutes, sort_order, screens) values ($L4W$m6$L4W$, $L4W$communication$L4W$, $L4W$Communication & listening$L4W$, $L4W$Communicating in digital & hybrid teams$L4W$, $L4W$Clear, calm, human — across chat and calls.$L4W$, 4, 6, $L4W$[{"kind":"hook","title":"Most of your leadership now happens in chat and calls","body":["In modern teams, your messages and calls are often the only way people experience you as a manager.","A rushed or unclear message can create confusion or anxiety faster than you think.","Good digital communication = clear, calm, and human."]},{"kind":"lesson","title":"Three rules for digital comms","points":[{"h":"Assume low context","p":"People can't see your face or hear your tone. Be explicit."},{"h":"Slow down reactions","p":"Don't fire off emotional messages. Use digital for clarity, not venting."},{"h":"Add a touch of human","p":"A 'thanks' or 'how are you doing?' goes a long way in chat."}],"note":"Write like someone will read it after a long day."},{"kind":"dragdrop","title":"Do these messages help or hurt?","prompt":"Sort each message into the right bucket.","leftLabel":"Helps clarity & trust","rightLabel":"Creates confusion or stress","items":[{"text":"'We need to talk. Call me.' (no context)","side":"right"},{"text":"'Quick sync at 3pm to review the client issue? Nothing urgent, just want to align.'","side":"left"},{"text":"'???' (sent after a delay)","side":"right"},{"text":"'Thanks for sending this. I've added comments — let's finalise by tomorrow.'","side":"left"},{"text":"'This is wrong.' (in a public channel)","side":"right"},{"text":"'Let's fix this together. I'll DM you to understand what happened.'","side":"left"}]},{"kind":"selfcheck","title":"My typical digital style is…","options":[{"text":"Very short, often no context — I just send what's on my mind.","response":"Fast, but risky. Tiny tweaks to context reduce a lot of stress."},{"text":"Sometimes clear, but when stressed I send rushed or sharp messages.","response":"You're aware of stress leaks. We'll add one pause step."},{"text":"Mostly clear and polite, but I could be more explicit about expectations.","response":"Good base. We'll sharpen your clarity and warmth."}]},{"kind":"scenario","title":"Scenario: the late-night message","setup":"It's 11pm. You remember a problem with tomorrow's client meeting and grab your phone to message the project channel.","question":"What do you actually send?","choices":[{"text":"'This deck is not good. We need to fix it before tomorrow.'","feedback":"High stress, low clarity. People may panic, work late, and still not know what to fix."},{"text":"'We have issues with tomorrow's deck. Fix it before the meeting.'","feedback":"Slightly clearer, but still invites a late-night scramble and anxiety."},{"text":"'Noticed a few issues with tomorrow's deck. Please don't work late — we'll review together at 9am. I'll add notes in the doc.'","feedback":"Balances urgency, clarity, and care. You give a plan and protect boundaries.","best":true}],"followUp":"Before you send, ask: is it clear on what and when? Am I creating unnecessary stress in how I say it?"},{"kind":"action","title":"Today's action: add context + care","intro":"For your next important message (email, Slack, WhatsApp), do this:","steps":["Start with context: 'Quick update about [topic]…'","Add a clear ask: 'What I need from you is…'","Add time framing: 'By [day], not urgent before then.'","Add a human line: 'Thanks for jumping on this.'"],"note":"You're making your messages feel like a calm leader, not a random alert."},{"kind":"reflect","title":"How did your clearer message land?","scaleQuestion":"How did people respond to your message?","scaleOptions":["Confused / many questions","Understood but stressed","Understood and calm","Appreciation or quick alignment"],"textPrompt":"What did you change in your wording compared to usual?","placeholder":"I changed…","closing":"In hybrid teams, people mostly see you through your words on a screen. Each clear, calm message builds your reputation."}]$L4W$::jsonb);
insert into public.locked_clusters (name, sort_order) values ($L4W$Expectations, delegation & time$L4W$, 1);
insert into public.locked_clusters (name, sort_order) values ($L4W$Feedback, coaching & performance$L4W$, 2);
insert into public.locked_clusters (name, sort_order) values ($L4W$Conflict, difficult people & well-being$L4W$, 3);
insert into public.locked_clusters (name, sort_order) values ($L4W$Team culture & collaboration$L4W$, 4);
insert into public.locked_clusters (name, sort_order) values ($L4W$Growing into a broader leader$L4W$, 5);
insert into public.assessment_questions (idx, skill, text_i18n) values (0, $L4W$communication$L4W$, $L4W${"en":"When I explain goals or tasks, my team can repeat back what success looks like in their own words.","hi":"जब मैं लक्ष्य या काम समझाता/समझाती हूँ, तो मेरी टीम अपने शब्दों में बता सकती है कि सफलता कैसी दिखती है।","te":"నేను లక్ష్యాలు లేదా పనులను వివరించినప్పుడు, విజయం ఎలా ఉంటుందో నా టీమ్ తమ సొంత మాటల్లో తిరిగి చెప్పగలదు."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (1, $L4W$communication$L4W$, $L4W${"en":"At the end of meetings, I confirm who is doing what by when, so people don't need to ask me again later.","hi":"मीटिंग के अंत में मैं तय करता/करती हूँ कि कौन क्या और कब तक करेगा, ताकि लोगों को बाद में दोबारा पूछना न पड़े।","te":"మీటింగ్ చివరిలో ఎవరు ఏం, ఎప్పటిలోగా చేయాలో నిర్ధారిస్తాను, తద్వారా వారు తర్వాత మళ్లీ అడగాల్సిన అవసరం ఉండదు."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (2, $L4W$communication$L4W$, $L4W${"en":"When I share a change or decision, I also explain the 'why', not just the instructions.","hi":"जब मैं कोई बदलाव या निर्णय साझा करता/करती हूँ, तो सिर्फ़ निर्देश नहीं, उसका 'क्यों' भी बताता/बताती हूँ।","te":"నేను మార్పు లేదా నిర్ణయాన్ని పంచుకున్నప్పుడు, కేవలం సూచనలే కాదు, దాని 'ఎందుకు' కూడా వివరిస్తాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (3, $L4W$listening$L4W$, $L4W${"en":"In 1:1s, I give my full attention — no notifications, no multitasking — and my team does most of the talking.","hi":"1:1 में मैं पूरा ध्यान देता/देती हूँ — कोई सूचना नहीं, कोई मल्टीटास्किंग नहीं — और ज़्यादातर मेरी टीम बोलती है।","te":"1:1లలో నేను పూర్తి శ్రద్ధ ఇస్తాను — నోటిఫికేషన్లు లేవు, మల్టీటాస్కింగ్ లేదు — ఎక్కువగా నా టీమ్ మాట్లాడుతుంది."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (4, $L4W$listening$L4W$, $L4W${"en":"When someone shares a concern, I ask questions to understand their view before suggesting solutions.","hi":"जब कोई चिंता साझा करता है, तो समाधान सुझाने से पहले मैं उनका नज़रिया समझने के लिए सवाल पूछता/पूछती हूँ।","te":"ఎవరైనా ఆందోళన పంచుకున్నప్పుడు, పరిష్కారాలు సూచించే ముందు వారి దృక్కోణాన్ని అర్థం చేసుకోవడానికి ప్రశ్నలడుగుతాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (5, $L4W$listening$L4W$, $L4W${"en":"In the last month, someone has told me — directly or indirectly — that they feel heard by me.","hi":"पिछले महीने किसी ने मुझे प्रत्यक्ष या अप्रत्यक्ष रूप से बताया कि वे मेरे सामने सुने हुए महसूस करते हैं।","te":"గత నెలలో, నా దగ్గర తాము వినబడుతున్నట్లు అనిపిస్తోందని ఎవరో నేరుగా లేదా పరోక్షంగా చెప్పారు."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (6, $L4W$delegation$L4W$, $L4W${"en":"In the last month, I've given a meaningful task to someone and let them own it without stepping back in to fix it.","hi":"पिछले महीने मैंने किसी को एक सार्थक काम सौंपा और बीच में सुधारने आए बिना उसे उसका स्वामी बनने दिया।","te":"గత నెలలో నేను ఒక ముఖ్యమైన పనిని ఎవరికైనా అప్పగించి, మధ్యలో సరిచేయడానికి జోక్యం చేసుకోకుండా దాన్ని వారు సొంతం చేసుకోనిచ్చాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (7, $L4W$delegation$L4W$, $L4W${"en":"When I delegate, I'm clear about the outcome, the timeline, and what they can decide on their own.","hi":"जब मैं काम सौंपता/सौंपती हूँ, तो परिणाम, समयसीमा और वे क्या ख़ुद तय कर सकते हैं — इस पर स्पष्ट रहता/रहती हूँ।","te":"నేను అప్పగించినప్పుడు, ఫలితం, గడువు, మరియు వారు సొంతంగా ఏం నిర్ణయించగలరో దానిపై స్పష్టంగా ఉంటాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (8, $L4W$delegation$L4W$, $L4W${"en":"My team can keep making progress even if I'm in back-to-back meetings or out for a day.","hi":"मेरी टीम तब भी प्रगति करती रह सकती है जब मैं लगातार मीटिंगों में या एक दिन के लिए बाहर हूँ।","te":"నేను వరుస మీటింగ్‌లలో లేదా ఒక రోజు బయట ఉన్నా నా టీమ్ తమ పనిలో ముందుకు సాగగలదు."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (9, $L4W$feedback$L4W$, $L4W${"en":"In the last 4 weeks, I've given specific feedback — what they did and the impact it had — to a team member.","hi":"पिछले 4 हफ़्तों में मैंने किसी टीम सदस्य को विशिष्ट फीडबैक दिया — उन्होंने क्या किया और उसका क्या असर हुआ।","te":"గత 4 వారాల్లో, ఒక టీమ్ సభ్యుడికి నిర్దిష్ట ఫీడ్‌బ్యాక్ ఇచ్చాను — వారు ఏం చేశారు, దాని ప్రభావం ఏమిటి."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (10, $L4W$feedback$L4W$, $L4W${"en":"I don't wait for formal reviews; I give small pieces of feedback during or right after the work.","hi":"मैं औपचारिक समीक्षा का इंतज़ार नहीं करता/करती; काम के दौरान या तुरंत बाद छोटे-छोटे फीडबैक देता/देती हूँ।","te":"నేను అధికారిక సమీక్షల కోసం వేచి ఉండను; పని సమయంలో లేదా వెంటనే చిన్న చిన్న ఫీడ్‌బ్యాక్‌లు ఇస్తాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (11, $L4W$feedback$L4W$, $L4W${"en":"I ask my team about their goals and help them see what will get them there.","hi":"मैं अपनी टीम से उनके लक्ष्यों के बारे में पूछता/पूछती हूँ और उन्हें दिखाता/दिखाती हूँ कि वहाँ क्या पहुँचाएगा।","te":"నా టీమ్‌ను వారి లక్ష్యాల గురించి అడిగి, అక్కడికి ఏం చేరుస్తుందో చూడటానికి సహాయం చేస్తాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (12, $L4W$conflict$L4W$, $L4W${"en":"When I notice tension or repeated issues between people, I bring it up rather than hoping it disappears.","hi":"जब मुझे लोगों के बीच तनाव या बार-बार की दिक़्क़तें दिखती हैं, तो मैं उसके ख़त्म होने की उम्मीद के बजाय उसे उठाता/उठाती हूँ।","te":"వ్యక్తుల మధ్య ఉద్రిక్తత లేదా పదేపదే సమస్యలు గమనించినప్పుడు, అది సమసిపోతుందని ఆశించకుండా దాన్ని లేవనెత్తుతాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (13, $L4W$conflict$L4W$, $L4W${"en":"In tough conversations, I stay calm and focused on the issue, not the person, even when emotions run high.","hi":"कठिन बातचीत में मैं शांत रहता/रहती हूँ और व्यक्ति नहीं, मुद्दे पर केंद्रित रहता/रहती हूँ, भले ही भावनाएँ तीव्र हों।","te":"కఠిన సంభాషణల్లో, భావోద్వేగాలు తీవ్రంగా ఉన్నా నేను ప్రశాంతంగా ఉండి, వ్యక్తిపై కాదు సమస్యపై దృష్టి పెడతాను."}$L4W$::jsonb);
insert into public.assessment_questions (idx, skill, text_i18n) values (14, $L4W$conflict$L4W$, $L4W${"en":"In the last 3 months, I've had at least one direct, honest conversation about performance or behaviour.","hi":"पिछले 3 महीनों में मैंने प्रदर्शन या व्यवहार के बारे में कम से कम एक सीधी, ईमानदार बातचीत की है।","te":"గత 3 నెలల్లో, పనితీరు లేదా ప్రవర్తన గురించి కనీసం ఒక నేరుగా, నిజాయితీగల సంభాషణ చేశాను."}$L4W$::jsonb);
insert into public.onboarding_questions (idx, text_i18n, options_i18n) values (0, $L4W${"en":"What's your main goal for using Lead4wd?","hi":"Lead4wd इस्तेमाल करने का आपका मुख्य लक्ष्य क्या है?","te":"Lead4wd వాడటానికి మీ ప్రధాన లక్ష్యం ఏమిటి?"}$L4W$::jsonb, $L4W${"en":["I'm a new manager and want guidance","I want to communicate more clearly","I need help with team conflict","I want to delegate more effectively"],"hi":["मैं नया प्रबंधक हूँ और मार्गदर्शन चाहता/चाहती हूँ","मैं और स्पष्ट रूप से संवाद करना चाहता/चाहती हूँ","मुझे टीम के टकराव में मदद चाहिए","मैं और प्रभावी ढंग से काम सौंपना चाहता/चाहती हूँ"],"te":["నేను కొత్త మేనేజర్‌ని, మార్గదర్శనం కావాలి","నేను మరింత స్పష్టంగా సంభాషించాలనుకుంటున్నాను","టీమ్ వివాదంలో నాకు సహాయం కావాలి","నేను మరింత ప్రభావవంతంగా అప్పగించాలనుకుంటున్నాను"]}$L4W$::jsonb);
insert into public.onboarding_questions (idx, text_i18n, options_i18n) values (1, $L4W${"en":"How much time can you give each week?","hi":"आप हर हफ़्ते कितना समय दे सकते हैं?","te":"ప్రతి వారం మీరు ఎంత సమయం ఇవ్వగలరు?"}$L4W$::jsonb, $L4W${"en":["10–15 minutes (micro-learning)","30–60 minutes","1–2 hours","More than 2 hours"],"hi":["10–15 मिनट (माइक्रो-लर्निंग)","30–60 मिनट","1–2 घंटे","2 घंटे से अधिक"],"te":["10–15 నిమిషాలు (మైక్రో-లెర్నింగ్)","30–60 నిమిషాలు","1–2 గంటలు","2 గంటల కంటే ఎక్కువ"]}$L4W$::jsonb);
